   175	    private static Set<Integer> getIndexesOfHeaderOrFootersContents(List<IObject> contents) {
   176	        Set<Integer> result = new HashSet<>(contents.size());
   177	        for (int pageNumber = 0; pageNumber < contents.size() - 1; pageNumber++) {
   178	            IObject currentObject = contents.get(pageNumber);
   179	            IObject nextObject = contents.get(pageNumber + 1);
   180	            if (currentObject != null && nextObject != null) {
   181	                if (arePossibleHeadersOrFooters(currentObject, nextObject, 1)) {
   182	                    result.add(pageNumber);
   183	                    result.add(pageNumber + 1);
   184	                }
   185	            }
   186	        }
   187	        //2-page style
   188	        for (int pageNumber = 0; pageNumber < contents.size() - 2; pageNumber++) {
   189	            IObject currentObject = contents.get(pageNumber);
   190	            IObject nextObject = contents.get(pageNumber + 2);
   191	            if (currentObject != null && nextObject != null) {
   192	                if (arePossibleHeadersOrFooters(currentObject, nextObject, 2)) {
   193	                    result.add(pageNumber);
   194	                    result.add(pageNumber + 2);
   195	                }
   196	            }
   197	        }
   198	        return result;
   199	    }
