   201	    /**
   202	     * Checks if a content object is a header or footer.
   203	     *
   204	     * @param content the content object to check
   205	     * @return true if the content is a header or footer, false otherwise
   206	     */
   207	    public static boolean isHeaderOrFooter(IObject content) {
   208	        if (content instanceof INode) {
   209	            INode node = (INode) content;
   210	            if (node.getSemanticType() == SemanticType.HEADER || node.getSemanticType() == SemanticType.FOOTER) {
   211	                return true;
   212	            }
   213	        }
   214	        return false;
   215	    }
   216	
   217	    private static List<IObject> filterHeaderOrFooterContents(List<IObject> contents, int pageNumber, boolean isHeaderDetection) {
   218	        BoundingBox boundingBox = DocumentProcessor.getPageBoundingBox(pageNumber);
   219	        if (boundingBox == null) {
   220	            return contents;
   221	        }
   222	        List<IObject> result = new ArrayList<>();
   223	        for (IObject content : contents) {
   224	            if (isHeaderDetection) {
   225	                if (content.getBottomY() < boundingBox.getHeight() * 2 / 3) {
   226	                    continue;
   227	                }
   228	            } else {
   229	                if (content.getTopY() > boundingBox.getHeight() / 3) {
   230	                    continue;
   231	                }
   232	            }
   233	            result.add(content);
   234	        }
   235	        return result;
   236	    }
   237	
   238	    private static boolean arePossibleHeadersOrFooters(IObject object1, IObject object2, int increment) {
   239	        if (object1 instanceof SemanticTextNode && object2 instanceof SemanticTextNode) {
   240	            SemanticTextNode textNode1 = (SemanticTextNode) object1;
   241	            SemanticTextNode textNode2 = (SemanticTextNode) object2;
   242	            if (!BoundingBox.areOverlapsBoundingBoxesExcludingPages(object1.getBoundingBox(), object2.getBoundingBox())) {
   243	                return false;
   244	            }
   245	            if (!NodeUtils.areCloseNumbers(textNode1.getFontSize(), textNode2.getFontSize())) {
   246	                return false;
   247	            }
   248	            if (Objects.equals(textNode1.getValue(), textNode2.getValue())) {
   249	                return true;
   250	            }
   251	            List<SemanticTextNode> textNodes = new ArrayList<>(2);
   252	            textNodes.add(textNode1);
   253	            textNodes.add(textNode2);
   254	            if (getHeadersOrFootersIntervals(textNodes, increment).size() == 1) {
   255	                return true;
   256	            }
   257	        } else if (object1 instanceof TextLine && object2 instanceof TextLine) {
   258	            TextLine line1 = (TextLine) object1;
   259	            TextLine line2 = (TextLine) object2;
   260	            SemanticTextNode textNode1 = new SemanticTextNode();
   261	            textNode1.add(line1);
   262	            SemanticTextNode textNode2 = new SemanticTextNode();
   263	            textNode2.add(line2);
   264	            return arePossibleHeadersOrFooters(textNode1, textNode2, increment);
   265	        } else {
   266	            if (BoundingBox.areSameBoundingBoxesExcludingPages(object1.getBoundingBox(), object2.getBoundingBox())) {
   267	                return true;
   268	            }
   269	        }
   270	        return false;
   271	    }
   272	
   273	    private static Set<ListInterval> getHeadersOrFootersIntervals(List<SemanticTextNode> textNodes, int increment) {
   274	        List<ListItemTextInfo> textChildrenInfo = new ArrayList<>(textNodes.size());
   275	        for (int i = 0; i < textNodes.size(); i++) {
   276	            SemanticTextNode textNode = textNodes.get(i);
   277	            TextLine line = textNode.getFirstNonSpaceLine();
   278	            TextLine secondLine = textNode.getNonSpaceLine(1);
   279	            textChildrenInfo.add(new ListItemTextInfo(i, textNode.getSemanticType(),
   280	                    line, line.getValue().trim(), secondLine == null));
   281	        }
   282	        Set<ListInterval> intervals = getHeadersOfFooterIntervals(textChildrenInfo, increment);
   283	        return intervals;
   284	    }
   285	
   286	    private static Set<ListInterval> getHeadersOfFooterIntervals(List<ListItemTextInfo> itemsInfo, int increment) {
   287	        ListIntervalsCollection listIntervals = new ListIntervalsCollection();
   288	        listIntervals.putAll((new AlfaLettersListLabelsDetectionAlgorithm1(increment)).getItemsIntervals(itemsInfo));
   289	        listIntervals.putAll((new AlfaLettersListLabelsDetectionAlgorithm2(increment)).getItemsIntervals(itemsInfo));
   290	        listIntervals.putAll((new KoreanLettersListLabelsDetectionAlgorithm(increment)).getItemsIntervals(itemsInfo));
   291	        listIntervals.putAll((new RomanNumbersListLabelsDetectionAlgorithm(increment)).getItemsIntervals(itemsInfo));
   292	        ArabicNumbersListLabelsDetectionAlgorithm arabicNumbersListLabelsDetectionAlgorithm = new ArabicNumbersListLabelsDetectionAlgorithm(increment);
   293	        arabicNumbersListLabelsDetectionAlgorithm.setHeaderOrFooterDetection(true);
   294	        listIntervals.putAll((arabicNumbersListLabelsDetectionAlgorithm).getItemsIntervals(itemsInfo));
   295	        ListIntervalsCollection correctIntervals = new ListIntervalsCollection(getEqualsItems(itemsInfo));
   296	        for (ListInterval listInterval : listIntervals.getSet()) {
   297	            List<String> labels = new LinkedList<>();
   298	            for (ListItemInfo info : listInterval.getListItemsInfos()) {
   299	                labels.add(((ListItemTextInfo) info).getListItem());
   300	            }
   301	            if (ListLabelsUtils.isListLabels(labels, increment)) {
   302	                correctIntervals.put(listInterval);
   303	            }
   304	        }
   305	        return correctIntervals.getSet();
   306	    }
   307	
   308	    private static Set<ListInterval> getEqualsItems(List<ListItemTextInfo> itemsInfo) {
   309	        Set<ListInterval> listIntervals = new HashSet<>();
   310	        String value = null;
   311	        ListInterval interval = new ListInterval();
   312	        for (ListItemTextInfo info : itemsInfo) {
   313	            if (!Objects.equals(info.getListItem(), value)) {
   314	                if (interval.getNumberOfListItems() > 1) {
   315	                    listIntervals.add(interval);
   316	                }
   317	                value = info.getListItem();
   318	                interval = new ListInterval();
   319	            }
   320	            interval.getListItemsInfos().add(info);
   321	        }
   322	        if (interval.getNumberOfListItems() > 1) {
   323	            listIntervals.add(interval);
   324	        }
   325	        return listIntervals;
   326	    }
   327	}
