   286	     * Sorts page contents by their bounding box positions.
   287	     *
   288	     * @param contents the list of content objects to sort
   289	     * @return a new sorted list of content objects
   290	     */
   291	    public static List<IObject> sortPageContents(List<IObject> contents) {
   292	        if (contents == null || contents.isEmpty()) {
   293	            return contents;
   294	        }
   295	        List<IObject> sortedContents = new ArrayList<>(contents);
   296	        sortedContents.sort((o1, o2) -> {
   297	            BoundingBox b1 = o1.getBoundingBox();
   298	            BoundingBox b2 = o2.getBoundingBox();
   299	            if (b1 == null && b2 == null) {
   300	                return 0;
   301	            }
   302	            if (b1 == null) {
   303	                return 1;
   304	            }
   305	            if (b2 == null) {
   306	                return -1;
   307	            }
   308	            if (!Objects.equals(b1.getPageNumber(), b2.getPageNumber())) {
   309	                return b1.getPageNumber() - b2.getPageNumber();
   310	            }
   311	            if (!Objects.equals(b1.getLastPageNumber(), b2.getLastPageNumber())) {
   312	                return b1.getLastPageNumber() - b2.getLastPageNumber();
   313	            }
   314	            if (!Objects.equals(b1.getTopY(), b2.getTopY())) {
   315	                return b2.getTopY() - b1.getTopY() > 0 ? 1 : -1;
   316	            }
   317	            if (!Objects.equals(b1.getLeftX(), b2.getLeftX())) {
   318	                return b1.getLeftX() - b2.getLeftX() > 0 ? 1 : -1;
   319	            }
   320	            if (!Objects.equals(b1.getBottomY(), b2.getBottomY())) {
   321	                return b1.getBottomY() - b2.getBottomY() > 0 ? 1 : -1;
   322	            }
   323	            if (!Objects.equals(b1.getRightX(), b2.getRightX())) {
   324	                return b1.getRightX() - b2.getRightX() > 0 ? 1 : -1;
   325	            }
   326	            return 0;
   327	        });
   328	        return sortedContents;
   329	    }
