   127	        if (content instanceof SemanticTextNode) {
   128	            SemanticTextNode textNode = (SemanticTextNode) content;
   129	            if (!textNode.isSpaceNode()) {
   130	                textNodes.add(textNode);
   131	                textNodeStatistics.addTextNode(textNode);
   132	            }
   133	        } else if (content instanceof TableBorder && ((TableBorder) content).isTextBlock()) {
   134	            TableBorder textBlock = (TableBorder) content;
   135	            TableBorderCell cell = textBlock.getCell(0, 0);
   136	            List<SemanticTextNode> cellTextNodes = getTextNodesFromContents(cell.getContents());
   137	            if (cellTextNodes.size() == 1) {
   138	                processContent(textNodes, cellTextNodes.get(0), textNodeStatistics, possibleHeadingsInList);
   139	            }
   140	        } else if (content instanceof PDFList) {
   141	            PDFList list = (PDFList) content;
   142	            ListItem listItem = list.getFirstListItem();
   143	            SemanticTextNode textNode = convertListItemToSemanticTextNode(listItem);
   144	            textNodes.add(textNode);
