   171	        for (int index = 0; index < contents.size(); index++) {
   172	            IObject content = contents.get(index);
   173	            if (content instanceof SemanticTextNode && ((INode) content).getSemanticType() == SemanticType.HEADING && !(content instanceof SemanticHeading)) {
   174	                SemanticHeading heading = new SemanticHeading((SemanticTextNode) content);
   175	                contents.set(index, heading);
   176	                StaticLayoutContainers.getHeadings().add(heading);
