   189	     * Detects and assigns heading levels based on text style.
   190	     * Groups headings by text style and assigns levels from 1 upwards.
   191	     */
   192	    public static void detectHeadingsLevels() {
   193	        SortedMap<TextStyle, Set<SemanticHeading>> map = new TreeMap<>();
   194	        List<SemanticHeading> headings = StaticLayoutContainers.getHeadings();
   195	        List<SemanticHeading> colorlessHeadings = new ArrayList<>();
   196	        for (SemanticHeading heading : headings) {
   197	            if (TextNodeUtils.getTextColorOrNull(heading) == null) {
   198	                colorlessHeadings.add(heading);
   199	                continue;
   200	            }
   201	            TextStyle textStyle = TextStyle.getTextStyle(heading);
   202	            map.computeIfAbsent(textStyle, k -> new HashSet<>()).add(heading);
   203	        }
   204	        int level = 1;
   205	        TextStyle previousTextStyle = null;
   206	        for (Map.Entry<TextStyle, Set<SemanticHeading>> entry : map.entrySet()) {
   207	            if (previousTextStyle != null && previousTextStyle.compareTo(entry.getKey()) != 0) {
   208	                level++;
   209	            }
   210	            previousTextStyle = entry.getKey();
   211	            for (SemanticHeading heading : entry.getValue()) {
   212	                heading.setHeadingLevel(level);
   213	            }
   214	        }
   215	        // Headings without color info get level based on font size relative to existing levels
   216	        for (SemanticHeading heading : colorlessHeadings) {
   217	            heading.setHeadingLevel(findClosestLevel(heading, map));
   218	        }
   219	    }
   220	
   221	    private static int findClosestLevel(SemanticHeading heading, SortedMap<TextStyle, Set<SemanticHeading>> map) {
   222	        if (map.isEmpty()) {
   223	            return 1;
   224	        }
   225	        double fontSize = heading.getFontSize();
   226	        int bestLevel = 1;
   227	        double bestDiff = Double.MAX_VALUE;
   228	        int level = 1;
   229	        TextStyle previousStyle = null;
   230	        for (Map.Entry<TextStyle, Set<SemanticHeading>> entry : map.entrySet()) {
   231	            if (previousStyle != null && previousStyle.compareTo(entry.getKey()) != 0) {
   232	                level++;
   233	            }
   234	            previousStyle = entry.getKey();
   235	            SemanticHeading representative = entry.getValue().iterator().next();
   236	            double diff = Math.abs(representative.getFontSize() - fontSize);
   237	            if (diff < bestDiff) {
   238	                bestDiff = diff;
   239	                bestLevel = level;
   240	            }
   241	        }
   242	        return bestLevel;
   243	    }
   244	}
