package org.opendataloader.pdf.processors;

import org.opendataloader.pdf.containers.StaticLayoutContainers;
import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.Test;
import org.verapdf.tools.StaticResources;
import org.verapdf.wcag.algorithms.entities.IObject;
import org.verapdf.wcag.algorithms.entities.SemanticHeaderOrFooter;
import org.verapdf.wcag.algorithms.entities.SemanticTextNode;
import org.verapdf.wcag.algorithms.entities.content.TextChunk;
import org.verapdf.wcag.algorithms.entities.content.TextLine;
import org.verapdf.wcag.algorithms.entities.enums.SemanticType;
import org.verapdf.wcag.algorithms.entities.geometry.BoundingBox;
import org.verapdf.wcag.algorithms.semanticalgorithms.containers.StaticContainers;

import java.util.ArrayList;
import java.util.List;

public class HeaderFooterProcessorTest {

    @Test
    public void testProcessHeadersAndFooters() {
        StaticContainers.setIsDataLoader(true);
        StaticContainers.setIsIgnoreCharactersWithoutUnicode(false);
        StaticResources.setDocument(null);
        StaticLayoutContainers.setCurrentContentId(0);
        List<List<IObject>> contents = new ArrayList<>();
        List<IObject> page1Contents = new ArrayList<>();
        page1Contents.add(new TextLine(new TextChunk(new BoundingBox(0, 10.0, 30.0, 20.0, 40.0),
            "Header", 10, 30.0)));
        page1Contents.add(new TextLine(new TextChunk(new BoundingBox(0, 10.0, 20.0, 20.0, 30.0),
            "Text", 10, 20.0)));
        page1Contents.add(new TextLine(new TextChunk(new BoundingBox(0, 10.0, 10.0, 20.0, 20.0),
            "Footer1", 10, 10.0)));
        List<IObject> page2Contents = new ArrayList<>();
        page2Contents.add(new TextLine(new TextChunk(new BoundingBox(1, 10.0, 30.0, 20.0, 40.0),
            "Header", 10, 30.0)));
        page2Contents.add(new TextLine(new TextChunk(new BoundingBox(1, 10.0, 20.0, 20.0, 30.0),
            "Different Text", 10, 20.0)));
        page2Contents.add(new TextLine(new TextChunk(new BoundingBox(1, 10.0, 10.0, 20.0, 20.0),
            "Footer2", 10, 10.0)));
        contents.add(page1Contents);
        contents.add(page2Contents);
        HeaderFooterProcessor.processHeadersAndFooters(contents, false);

        Assertions.assertEquals(3, contents.get(0).size());
        Assertions.assertEquals(3, contents.get(1).size());

        Assertions.assertTrue(contents.get(0).get(0) instanceof SemanticHeaderOrFooter);
        Assertions.assertEquals(SemanticType.HEADER, ((SemanticHeaderOrFooter) contents.get(0).get(0)).getSemanticType());
        Assertions.assertTrue(contents.get(1).get(0) instanceof SemanticHeaderOrFooter);
        Assertions.assertEquals(SemanticType.HEADER, ((SemanticHeaderOrFooter) contents.get(1).get(0)).getSemanticType());
        Assertions.assertTrue(contents.get(0).get(2) instanceof SemanticHeaderOrFooter);
        Assertions.assertEquals(SemanticType.FOOTER, ((SemanticHeaderOrFooter) contents.get(0).get(2)).getSemanticType());
        Assertions.assertTrue(contents.get(1).get(2) instanceof SemanticHeaderOrFooter);
        Assertions.assertEquals(SemanticType.FOOTER, ((SemanticHeaderOrFooter) contents.get(1).get(2)).getSemanticType());
    }

    /**
     * Tests that footer detection does NOT absorb body text that happens
     * to match across consecutive pages at the same relative position.
     *
     * Scenario: Two pages have matching footers at position 0 (last item)
     * AND matching body text at position 1 (second-to-last). With the
     * cascade limited, only the actual footer (position 0) should be
     * detected, not the body text.
     *
     * This reproduces the issue where a note like "※ 출수 중..." at the
     * same bottom-relative position on consecutive pages was being
     * absorbed into the footer bounding box.
     */
    @Test
    public void testFooterDoesNotAbsorbBodyTextOnCascade() {
        StaticContainers.setIsDataLoader(true);
        StaticContainers.setIsIgnoreCharactersWithoutUnicode(false);
        StaticResources.setDocument(null);
        StaticLayoutContainers.setCurrentContentId(0);

        // Simulate 3 pages: pages 19, 20, 21 from the CERAGEM BALANCE manual
        // Each page has: [body text...] [note at position 1] [footer at position 0]
        // On pages 19-20, the note is present and matches. On page 21, no matching note.
        List<List<IObject>> contents = new ArrayList<>();

        // Page 19: body text, note, footer
        List<IObject> page19 = new ArrayList<>();
        page19.add(new TextLine(createTextChunk(0, 100.0, 700.0, 200.0, 800.0, "Body text 19")));
        page19.add(new TextLine(createTextChunk(0, 100.0, 116.0, 200.0, 136.0, "Note text that repeats")));
        page19.add(new TextLine(createTextChunk(0, 100.0, 34.0, 200.0, 43.0, "19 CERAGEM BALANCE USER MANUAL")));

        // Page 20: body text, note (same as page 19), footer
        List<IObject> page20 = new ArrayList<>();
        page20.add(new TextLine(createTextChunk(1, 100.0, 700.0, 200.0, 800.0, "Body text 20")));
        page20.add(new TextLine(createTextChunk(1, 100.0, 116.0, 200.0, 136.0, "Note text that repeats")));
        page20.add(new TextLine(createTextChunk(1, 100.0, 34.0, 200.0, 43.0, "20 CERAGEM BALANCE USER MANUAL")));

        // Page 21: body text, no matching note, footer
        List<IObject> page21 = new ArrayList<>();
        page21.add(new TextLine(createTextChunk(2, 100.0, 700.0, 200.0, 800.0, "Body text 21")));
        page21.add(new TextLine(createTextChunk(2, 100.0, 500.0, 200.0, 520.0, "Different body text")));
        page21.add(new TextLine(createTextChunk(2, 100.0, 34.0, 200.0, 43.0, "21 CERAGEM BALANCE USER MANUAL")));

        contents.add(page19);
        contents.add(page20);
        contents.add(page21);

        HeaderFooterProcessor.processHeadersAndFooters(contents, false);

        // All pages should have 3 items (header may be null if no header detected)
        // But footers should each contain only 1 content item (the actual footer text)
        // The note should NOT be absorbed into the footer
        for (int i = 0; i < 3; i++) {
            List<IObject> pageContents = contents.get(i);
            // Find the footer
            SemanticHeaderOrFooter footer = null;
            for (IObject obj : pageContents) {
                if (obj instanceof SemanticHeaderOrFooter
                    && ((SemanticHeaderOrFooter) obj).getSemanticType() == SemanticType.FOOTER) {
                    footer = (SemanticHeaderOrFooter) obj;
                    break;
                }
            }
            Assertions.assertNotNull(footer, "Page " + (i + 18) + " should have a footer detected");

            // Footer should contain exactly 1 item (the footer text), NOT the note
            Assertions.assertEquals(1, footer.getContents().size(),
                "Page " + (i + 18) + " footer should contain only 1 item, not absorb body text");
        }
    }

    private static TextChunk createTextChunk(int pageNum, double leftX, double bottomY,
                                              double rightX, double topY, String text) {
        TextChunk chunk = new TextChunk(new BoundingBox(pageNum, leftX, bottomY, rightX, topY),
            text, 10, 10.0);
        return chunk;
    }
}

